import React from 'react';
import { View, Text, StyleSheet, Pressable } from 'react-native';
import Animated, {
  useSharedValue,
  useAnimatedStyle,
  withSpring,
  withSequence,
  withRepeat,
  withTiming,
} from 'react-native-reanimated';
import { usePetStore } from '../../stores/petStore';
import { COLORS, FONT_SIZES } from '../../constants/theme';
import { STATUS_THRESHOLDS } from '../../types/pet';

const PET_EMOJIS: Record<string, string> = {
  baby: '🐣',
  young: '🐥',
  adult: '🐔',
  evolved: '🦅',
};

const FACE_EMOJIS: Record<string, string> = {
  happy: '😄',
  normal: '😐',
  worried: '😟',
  critical: '😢',
  sick: '🤒',
};

interface PetSpriteProps {
  onInteract?: () => void;
}

export const PetSprite: React.FC<PetSpriteProps> = ({ onInteract }) => {
  const pet = usePetStore();
  const scale = useSharedValue(1);
  const rotation = useSharedValue(0);
  const bounce = useSharedValue(0);

  const petEmoji = PET_EMOJIS[pet.stage] || PET_EMOJIS.baby;

  const getFace = () => {
    const minStatus = Math.min(pet.hunger, pet.thirst, pet.hygiene, pet.mood);
    if (minStatus <= 0) return FACE_EMOJIS.sick;
    if (minStatus < STATUS_THRESHOLDS.worried) return FACE_EMOJIS.critical;
    if (minStatus < STATUS_THRESHOLDS.normal) return FACE_EMOJIS.worried;
    if (minStatus < STATUS_THRESHOLDS.happy) return FACE_EMOJIS.normal;
    return FACE_EMOJIS.happy;
  };

  const handlePet = () => {
    scale.value = withSequence(withTiming(1.2, { duration: 100 }), withSpring(1));
    rotation.value = withSequence(withTiming(10, { duration: 100 }), withTiming(-10, { duration: 100 }), withTiming(0, { duration: 100 }));
    pet.pet();
    onInteract?.();
  };

  React.useEffect(() => {
    bounce.value = withRepeat(withSequence(withTiming(-10, { duration: 1000 }), withTiming(0, { duration: 1000 })), -1, true);
  }, []);

  const animatedStyle = useAnimatedStyle(() => ({
    transform: [{ scale: scale.value }, { rotate: `${rotation.value}deg` }, { translateY: bounce.value }],
  }));

  return (
    <Pressable onPress={handlePet} style={styles.container}>
      <Animated.View style={[styles.petContainer, animatedStyle]}>
        <Text style={styles.petEmoji}>{petEmoji}</Text>
        <View style={styles.faceContainer}>
          <Text style={styles.faceEmoji}>{getFace()}</Text>
        </View>
      </Animated.View>
      <Text style={styles.tapHint}>点击抚摸 ✋</Text>
    </Pressable>
  );
};

const styles = StyleSheet.create({
  container: { alignItems: 'center', justifyContent: 'center', padding: 20 },
  petContainer: { width: 150, height: 150, alignItems: 'center', justifyContent: 'center', backgroundColor: COLORS.primaryLight, borderRadius: 75 },
  petEmoji: { fontSize: 80 },
  faceContainer: { position: 'absolute', bottom: 20, right: 10, backgroundColor: COLORS.card, borderRadius: 20, padding: 4 },
  faceEmoji: { fontSize: 24 },
  tapHint: { marginTop: 16, fontSize: FONT_SIZES.sm, color: COLORS.textLight },
});
